# CMU single-map runtime for virtual DualSense USB over physical DualSense Bluetooth.
# The app is a generic interpreter for this file: routes, reports, offsets,
# constants, channel split, codec settings, and output assembly live here.

[map]
id = ds5_usb_over_ds5_bt
version = 1
virtual_device = ds5_usb
physical_device = ds5_bt

[usb.endpoints]
hid_in = 0x84
hid_out = 0x03
iso_out = 0x01
iso_in = 0x82

[path.input.controller_to_virtual]
trigger = physical.read
source_report = 0x31
destination_endpoint = 0x84
destination_report = 0x01
destination_length = 64
copy = source[2..64] -> destination[1..63]
drop = source[0], source[1], source[last-3..last]

[path.output.virtual_to_controller]
trigger = usb.endpoint.hid_out
source_endpoint = 0x03
source_report = 0x02
destination_report = 0x31
destination_length = 78
tag = 0x10
sequence = high_nibble
copy = source[1..47] -> destination[3..49]
fill = destination[50..73] = 0x00
tail = crc32.hid_output seed=0xa2 destination[74..77]

[path.control.feature_get]
trigger = usb.ep0.GET_REPORT
cache_on_connect = false
if_cached = respond_from_cache
if_missing = stall

[path.control.feature_set]
trigger = usb.ep0.SET_REPORT
cache_written_reports = true
if_unknown = log_and_ack

[path.control.usb_control_map]
# Direct USB feature GETs are routed by map. The app only executes these rules:
# match USB request, perform physical HID action, return the mapped response.
rule.1.match = usb.feature_get report=0x05
rule.1.action.1 = physical.hid.get_feature report=0x05 length=41
rule.1.response = usb.respond physical length=41
rule.1.cacheable_info = true
rule.1.preload = true

rule.2.match = usb.feature_get report=0x08
rule.2.action.1 = physical.hid.get_feature report=0x08 length=48
rule.2.response = usb.respond physical length=48
rule.2.cacheable_info = true
rule.2.preload = true

rule.3.match = usb.feature_get report=0x09
rule.3.action.1 = physical.hid.get_feature report=0x09 length=20
rule.3.response = usb.respond physical length=20
rule.3.cacheable_info = true
rule.3.preload = true

rule.4.match = usb.feature_get report=0x0a
rule.4.action.1 = physical.hid.get_feature report=0x0a length=27
rule.4.response = usb.respond physical length=27
rule.4.cacheable_info = true

rule.5.match = usb.feature_get report=0x0b
rule.5.action.1 = physical.hid.get_feature report=0x0b length=42
rule.5.response = usb.respond physical length=42
rule.5.cacheable_info = true
rule.5.preload = true

rule.6.match = usb.feature_get report=0x0c
rule.6.action.1 = physical.hid.get_feature report=0x0c length=42
rule.6.response = usb.respond physical length=42
rule.6.cacheable_info = true

rule.7.match = usb.feature_get report=0x20
rule.7.action.1 = physical.hid.get_feature report=0x20 length=64
rule.7.response = usb.respond physical length=64
rule.7.cacheable_info = true
rule.7.preload = true

rule.8.match = usb.feature_get report=0x21
rule.8.action.1 = physical.hid.get_feature report=0x21 length=5
rule.8.response = usb.respond physical length=5
rule.8.cacheable_info = true

rule.9.match = usb.feature_get report=0x22
rule.9.action.1 = physical.hid.get_feature report=0x22 length=64
rule.9.response = usb.respond physical length=64
rule.9.cacheable_info = true
rule.9.preload = true

rule.10.match = usb.feature_get report=0x80
# 0x80 is the page selector. Not preloaded so we don't clobber whatever
# selector DriftGuard set right before issuing GET 0x81.
rule.10.action.1 = physical.hid.get_feature report=0x80 length=64
rule.10.response = usb.respond physical length=64
rule.10.cacheable_info = true

rule.11.match = usb.feature_get report=0x81
# Selector-gated: the per-page selector lives in [path.control.feature_pages].
# This fallback only runs when no selector has been set; the page-rule path
# emits SET 0x80 + GET 0x81 dynamically.
rule.11.action.1 = physical.hid.get_feature report=0x81 length=64
rule.11.response = usb.respond physical length=64
rule.11.cacheable_info = true

rule.12.match = usb.feature_get report=0x82
rule.12.action.1 = physical.hid.get_feature report=0x82 length=10
rule.12.response = usb.respond physical length=10
rule.12.cacheable_info = true
rule.12.preload = true

rule.13.match = usb.feature_get report=0x83
rule.13.action.1 = physical.hid.get_feature report=0x83 length=64
rule.13.response = usb.respond physical length=64
rule.13.cacheable_info = true
rule.13.preload = true

rule.14.match = usb.feature_get report=0x84
rule.14.action.1 = physical.hid.get_feature report=0x84 length=64
rule.14.response = usb.respond physical length=64
rule.14.cacheable_info = true

rule.15.match = usb.feature_get report=0x85
rule.15.action.1 = physical.hid.get_feature report=0x85 length=3
rule.15.response = usb.respond physical length=3
rule.15.cacheable_info = true

rule.16.match = usb.feature_get report=0xa0
rule.16.action.1 = physical.hid.get_feature report=0xa0 length=2
rule.16.response = usb.respond physical length=2
rule.16.cacheable_info = true

rule.17.match = usb.feature_get report=0xe0
rule.17.action.1 = physical.hid.get_feature report=0xe0 length=64
rule.17.response = usb.respond physical length=64
rule.17.cacheable_info = true

rule.18.match = usb.feature_get report=0xf0
rule.18.action.1 = physical.hid.get_feature report=0xf0 length=64
rule.18.response = usb.respond physical length=64
rule.18.cacheable_info = true
rule.18.preload = true

rule.19.match = usb.feature_get report=0xf1
rule.19.action.1 = physical.hid.get_feature report=0xf1 length=64
rule.19.response = usb.respond physical length=64
rule.19.cacheable_info = true
rule.19.preload = true

rule.20.match = usb.feature_get report=0xf2
rule.20.action.1 = physical.hid.get_feature report=0xf2 length=16
rule.20.response = usb.respond physical length=16
rule.20.cacheable_info = true
rule.20.preload = true

rule.21.match = usb.feature_get report=0xf4
rule.21.action.1 = physical.hid.get_feature report=0xf4 length=64
rule.21.response = usb.respond physical length=64
rule.21.cacheable_info = true
rule.21.preload = true

rule.22.match = usb.feature_get report=0xf5
rule.22.action.1 = physical.hid.get_feature report=0xf5 length=4
rule.22.response = usb.respond physical length=4
rule.22.cacheable_info = true

[path.connect.actions]

[path.control.feature_pages]
selector_report = 0x80
# When physical_selector_report is set, a page whose physical_set_selector=true
# will first issue HidD_SetFeature(physical_selector_report, selector bytes),
# optionally signed by physical_selector_crc, before HidD_GetFeature.
physical_selector_report = 0x80
physical_selector_length = 64
physical_selector_crc = crc32.hid_feature_set seed=0x53 tail=last4

# USB SET_REPORT 0x80 selects DS5 info pages. Later USB GET_REPORT 0x81
# triggers an on-demand physical BT request: signed SET 0x80 selector, then
# plain GET 0x81. The 0x81 prefixes below are response validation only.
page.1.selector = 01 13 01
page.1.response_report = 0x81
page.1.response_length = 64
page.1.response_prefix = 01 13 02
page.1.physical_report = 0x81
page.1.physical_request_length = 64
page.1.physical_set_selector = true

page.2.selector = 70 01
page.2.response_report = 0x81
page.2.response_length = 64
page.2.response_prefix = 70 01 03 00
page.2.physical_report = 0x81
page.2.physical_request_length = 64
page.2.physical_set_selector = true

page.3.selector = 04 03
page.3.response_report = 0x81
page.3.response_length = 64
page.3.response_prefix = 04 03 02
page.3.physical_report = 0x81
page.3.physical_request_length = 64
page.3.physical_set_selector = true

page.4.selector = 03 03
page.4.ack_only = true

page.5.selector = 06 04
page.5.ack_only = true

page.6.selector = 06 02 01 01
page.6.ack_only = true

page.7.selector = 06 02 00 01
page.7.ack_only = true

[path.control.audio_state]
trigger = usb.ep0.class_out
primitive = control.uac1_feature_unit_to_state
speaker_feature_unit = 2
headset_feature_unit = 5
mute_control = 1
volume_control = 2
volume_to_physical = q8_8_db_to_byte

[path.control.uac1_feature_units]
trigger = usb.ep0.class_interface
audio_control_interface = 0
speaker_unit = 2
headset_unit = 5
mute_control = 1
volume_control = 2

# UAC1 volume values are signed Q8.8 dB.
speaker.mute.default = 0
speaker.volume.default = -25600
speaker.volume.min = -25600
speaker.volume.max = 0
speaker.volume.res = 0x0100

headset.mute.default = 0
headset.volume.default = 0
headset.volume.min = 0
headset.volume.max = 12288
headset.volume.res = 122

[path.control.uac1_endpoint_sample_freq]
trigger = usb.ep0.class_endpoint
sample_freq_control = 1

endpoint.0x01.default = 48000
endpoint.0x01.min = 48000
endpoint.0x01.max = 48000
endpoint.0x01.res = 0

endpoint.0x82.default = 48000
endpoint.0x82.min = 48000
endpoint.0x82.max = 48000
endpoint.0x82.res = 0

[path.iso.virtual_to_physical_stream]
trigger = usb.endpoint.iso_out
source_endpoint = 0x01
source_format = pcm_s16le_interleaved
# Sample rate of the PCM the map ops actually see. The USB ISO endpoint
# declares 48 kHz to Windows, but the app's ingest stage resamples all
# 4 channels 48 kHz -> reservoir_sample_rate before pushing into the
# intermediate reservoir.
sample_rate = 45000
# Change this for custom timing probes. Packet audio duration is
# frame_samples / reservoir_sample_rate, so 480 at 45000 Hz is 10.667 ms.
reservoir_sample_rate = 45000
channels = 4
# Number of bytes the builder pulls from the reservoir per BT 0x36 frame.
# 480 samples x 4 channels x 2 bytes = 3840 (= 10.884 ms of source audio at
# 44.1 kHz). The number is unchanged from the previous 48 kHz design --
# only the content clock inside the 3840 bytes changes with reservoir_sample_rate.
expected_urb_bytes = 3840
frame_samples = 480
# bt_pace_ms = starting wall-clock spacing between outbound BT 0x36 frames.
# The feedback loop (see below) drives this toward the true producer rate
# by tracking reservoir velocity, so this is just the initial guess. Pick
# something close to the expected equilibrium for a fast warm-up:
#   10.667 = 480 / 45000, stable probe that measured roughly +50 cents.
#   10.738 = 480 / 44700, downshift probe from the stable 45 kHz region.
#   10.561 = 480 / 45450, 10 MHz / 220 rounded to a clean 15:1 rate.
#   10.667 = DSX-measured wall cadence (good if Windows feeds at ~98% rt).
#   10.884 = exact 480 / 44.1 kHz match (good if Windows feeds at 100% rt).

# iso_out_completion_delay_us = how long the driver waits before completing
# each ISO OUT URB. Kept close to bt_pace_ms so the driver does not feed
# the app faster than the BT writer can drain; the reservoir absorbs the
# small remaining mismatch.
iso_out_completion_delay_us = 9650
iso_out_completion_delay_scale = 1.0
#iso_out_completion_delay_us = 5730

# === Intermediate reservoir ===
# Ring buffer between the ingest thread (48 kHz -> reservoir_sample_rate
# resample) and the builder thread (pulls 480 x 4-ch chunks). Decouples ISO arrival jitter
# and kernel BT stack stalls from the BT emit cadence.
#
# warmup_ms = how much audio the reservoir must hold before the builder is
# allowed to start pulling. Smaller = closer to "live" but less tolerance
# to a cold-start hiccup. The system is designed to ride near empty (just
# above the per-frame pull size of ~10.884 ms), so warmup just needs to
# clear enough room for the very first pull plus a hair of headroom.
# max_ms = hard cap; ingest drops oldest samples to make room above this.
intermediate_buffer_warmup_ms = 20
intermediate_buffer_max_ms = 200

# === Adaptive pace feedback (velocity-based, rate-matching) ===
# The writer adjusts bt_pace_ms within [pace_min_ms, pace_max_ms] every
# pace_adjust_interval_frames frames. Goal is to keep the reservoir
# *nearly empty* (the reservoir exists to absorb jitter, not to buffer
# audio); long-term, consumer rate must equal producer rate or fill drifts.
#
# Control law on every feedback tick:
#   1. Hard limits dominate. If fill < pace_hard_min_fill_ms the writer is
#      consuming too fast -> slow it down by pace_adjust_step_ms times
#      pace_hard_step_multiplier (so panic moves are larger than normal
#      ones). If fill > pace_hard_max_fill_ms the writer is consuming too
#      slow -> speed it up by the same magnified step.
#   2. Inside the safe band [hard_min, hard_max] we react to *velocity*,
#      not position. dfill = fill_now - fill_at_previous_tick.
#        dfill >  pace_velocity_deadband_ms  -> reservoir is growing, the
#                                               writer is slower than the
#                                               producer -> shrink pace
#                                               (write more often).
#        dfill < -pace_velocity_deadband_ms  -> reservoir is shrinking, the
#                                               writer is faster than the
#                                               producer -> grow pace
#                                               (write less often).
#        |dfill| <= deadband                 -> rates match, leave pace.
# Zeroing dfill is exactly the producer/consumer rate match we want.
pace_adjust_step_ms = 0.01
pace_adjust_interval_frames = 1
#bt_pace_ms = 10.2
#pace_min_ms = 9.4
#pace_max_ms = 10.5
bt_pace_ms     = 10.667
audio_builder_pace_ms = 0.0
pace_min_ms    = 7.5
pace_max_ms    = 10.9
pace_hard_min_fill_ms = 5
pace_hard_max_fill_ms = 40
pace_hard_step_multiplier = 5
pace_velocity_deadband_ms = 1

physical_report_id = 0x36
physical_report_length = 398
opus_sample_rate = 48000
opus_frame_samples = 480
state_block_id = 0x90
timing_block_id = 0x91
audio_block_id = 0x95
haptic_block_id = 0x92
opus_payload_bytes = 200
# Haptic chain output rate. Was 3200 (when input was 48 kHz, ratio 15:1);
# at the current 45000 Hz probe the same 15:1 ratio gives 3000 Hz on the wire.
# The DS5 hardware does not care about the absolute label -- it consumes
# the bytes at whatever clock its haptic engine runs at, so the perceived
# haptic timing follows the same custom reservoir clock as the opus stream.
haptic_output_rate = 3000

buffers = physical_report, state_block, timing_block, audio_block, haptic_block, speaker_pcm, haptic_pcm, opus_payload, haptic_s8
op.1 = pcm.select_channels usb_iso_pcm channels=0,1 out=speaker_pcm
# speaker_pcm is already at reservoir_sample_rate coming out of the reservoir (ingest does
# the resample once, globally), so no per-frame resample op here. The Opus
# encoder is configured at 48 kHz nominal to land samples on the DS5's
# BT DAC at the probed pitch/timing point.
op.2 = codec.opus_encode speaker_pcm sample_rate=48000 channels=2 frame_samples=480 bytes=200 out=opus_payload
op.3 = bytes.clear audio_block
op.4 = bytes.set audio_block offset=0 source=audio_block_id
op.5 = bytes.set audio_block offset=1 source=len(opus_payload)
op.6 = bytes.copy opus_payload src=0..199 target=audio_block dst=2
op.7 = pcm.select_channels usb_iso_pcm channels=2,3 out=haptic_pcm
op.8 = pcm.downsample haptic_pcm from=45000 to=3000 method=average out=haptic_pcm_3k2
op.9 = pcm.s16_to_s8 haptic_pcm_3k2 out=haptic_s8
op.10 = bytes.clear haptic_block
op.11 = bytes.set haptic_block offset=0 source=haptic_block_id
op.12 = bytes.set haptic_block offset=1 source=payload_len(haptic_block)
op.13 = bytes.copy haptic_s8 src=0..63 target=haptic_block dst=2
op.14 = bytes.clear state_block
op.15 = bytes.set state_block offset=0 source=state_block_id
op.16 = bytes.set state_block offset=1 source=payload_len(state_block)
op.17 = bytes.copy output_effects_payload src=0..46 target=state_block dst=2
op.18 = bytes.clear timing_block
op.19 = bytes.set timing_block offset=0 source=timing_block_id
op.20 = bytes.set timing_block offset=1 source=payload_len(timing_block)
op.21 = bytes.set timing_block offset=2 value=0xfe
op.22 = bytes.set timing_block offset=3 source=audio_latency
op.23 = bytes.set timing_block offset=4 source=audio_latency
op.24 = bytes.set timing_block offset=5 source=audio_latency
op.25 = bytes.set timing_block offset=6 source=audio_latency
op.26 = bytes.set timing_block offset=7 source=audio_latency
op.27 = bytes.set timing_block offset=8 source=audio_sequence++
op.28 = physical_report.clear
op.29 = physical_report.header report=0x36 seq=high_nibble
op.30 = block.append state_block
op.31 = block.append timing_block
op.32 = block.append_if_present audio_block payload=2..201
# Channels 2/3 are a real stream lane; silence is still valid payload data.
op.33 = block.append haptic_block
op.34 = crc32.hid_output seed=0xa2 target=physical_report tail=last4
emit = physical.write physical_report

# === CTM Bridge advertise manifest ===
# Read by the Moonlight overlay (TV side) to decide which per-controller
# controls to render. Free-form key=value, parsed only when CTM mode is
# active. Modes (if any) declared in [mode.*] sections below.
[advertise]
controller_name = DualSense
vendor = Sony
rumble = true
leds = true
adaptive_triggers = true
haptics = true
audio_output = true
audio_input = false
audio_redirect = true
volume_control_speaker = true
volume_control_headphone = true
audio_route_modes = off, headphones, speaker, both, split
latency_adjustable_ms = 20..200
battery = true
stop_sniff_rate = true
# overlay_settings = ordered list of rows the overlay should render
# inside the expanded card. Engine knows how to render each token.
overlay_settings = latency, audio_redirect, volume_speaker, volume_headphone
